import{_ as t,o as l,c as e,a2 as r}from"./chunks/framework.BQ1gajhD.js";const m=JSON.parse('{"title":"北京名胜古迹","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/index.md","filePath":"landmarks/index.md","lastUpdated":null}'),i={name:"landmarks/index.md"};function n(o,a,s,d,h,g){return l(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="北京名胜古迹" tabindex="-1">北京名胜古迹 <a class="header-anchor" href="#北京名胜古迹" aria-label="Permalink to &quot;北京名胜古迹&quot;">​</a></h1><blockquote><p>&quot;千年帝都，古迹如云。&quot;</p></blockquote><p>北京作为六朝古都，拥有丰富的历史文化遗产。从皇家宫殿到万里长城，从祭天圣地到园林杰作，每一处古迹都诉说着中华文明的辉煌。</p><h2 id="皇家建筑" tabindex="-1">皇家建筑 <a class="header-anchor" href="#皇家建筑" aria-label="Permalink to &quot;皇家建筑&quot;">​</a></h2><h3 id="故宫博物院" tabindex="-1"><a href="/beijing-travel-guide/landmarks/forbidden-city.html">故宫博物院</a> <a class="header-anchor" href="#故宫博物院" aria-label="Permalink to &quot;[故宫博物院](/landmarks/forbidden-city)&quot;">​</a></h3><p>世界最大宫殿建筑群，明清两代皇宫，世界文化遗产。</p><ul><li><strong>门票</strong>：旺季60元，淡季40元</li><li><strong>建议时长</strong>：半天至一天</li><li><strong>看点</strong>：太和殿、乾清宫、御花园、珍宝馆</li></ul><h3 id="天坛" tabindex="-1"><a href="/beijing-travel-guide/landmarks/temple-of-heaven.html">天坛</a> <a class="header-anchor" href="#天坛" aria-label="Permalink to &quot;[天坛](/landmarks/temple-of-heaven)&quot;">​</a></h3><p>明清皇帝祭天祈谷之地，世界文化遗产。</p><ul><li><strong>门票</strong>：联票28元</li><li><strong>建议时长</strong>：3-4小时</li><li><strong>看点</strong>：祈年殿、回音壁、圜丘坛</li></ul><h3 id="颐和园" tabindex="-1"><a href="/beijing-travel-guide/landmarks/summer-palace.html">颐和园</a> <a class="header-anchor" href="#颐和园" aria-label="Permalink to &quot;[颐和园](/landmarks/summer-palace)&quot;">​</a></h3><p>中国古典园林巅峰之作，世界文化遗产。</p><ul><li><strong>门票</strong>：联票60元</li><li><strong>建议时长</strong>：半天至一天</li><li><strong>看点</strong>：佛香阁、长廊、十七孔桥、昆明湖</li></ul><h3 id="圆明园" tabindex="-1"><a href="/beijing-travel-guide/landmarks/yuanmingyuan.html">圆明园</a> <a class="header-anchor" href="#圆明园" aria-label="Permalink to &quot;[圆明园](/landmarks/yuanmingyuan)&quot;">​</a></h3><p>&quot;万园之园&quot;遗址，爱国主义教育基地。</p><ul><li><strong>门票</strong>：联票25元</li><li><strong>建议时长</strong>：半天至一天</li><li><strong>看点</strong>：西洋楼遗址、大水法、十二生肖</li></ul><h3 id="北海公园" tabindex="-1"><a href="/beijing-travel-guide/landmarks/beihai.html">北海公园</a> <a class="header-anchor" href="#北海公园" aria-label="Permalink to &quot;[北海公园](/landmarks/beihai)&quot;">​</a></h3><p>现存最古老皇家园林，白塔琼岛。</p><ul><li><strong>门票</strong>：联票20元</li><li><strong>建议时长</strong>：2-3小时</li><li><strong>看点</strong>：白塔、九龙壁、让我们荡起双桨</li></ul><h3 id="景山公园" tabindex="-1"><a href="/beijing-travel-guide/landmarks/jingshan.html">景山公园</a> <a class="header-anchor" href="#景山公园" aria-label="Permalink to &quot;[景山公园](/landmarks/jingshan)&quot;">​</a></h3><p>北京内城制高点，俯瞰紫禁城最佳位置。</p><ul><li><strong>门票</strong>：2元</li><li><strong>建议时长</strong>：1-2小时</li><li><strong>看点</strong>：万春亭、崇祯自缢处</li></ul><h2 id="长城" tabindex="-1">长城 <a class="header-anchor" href="#长城" aria-label="Permalink to &quot;长城&quot;">​</a></h2><h3 id="八达岭长城" tabindex="-1"><a href="/beijing-travel-guide/landmarks/badaling.html">八达岭长城</a> <a class="header-anchor" href="#八达岭长城" aria-label="Permalink to &quot;[八达岭长城](/landmarks/badaling)&quot;">​</a></h3><p>万里长城精华段，最早开放的长城。</p><ul><li><strong>门票</strong>：40元</li><li><strong>建议时长</strong>：3-4小时</li><li><strong>看点</strong>：北八楼、好汉坡、关城</li></ul><h3 id="慕田峪长城" tabindex="-1"><a href="/beijing-travel-guide/landmarks/mutianyu.html">慕田峪长城</a> <a class="header-anchor" href="#慕田峪长城" aria-label="Permalink to &quot;[慕田峪长城](/landmarks/mutianyu)&quot;">​</a></h3><p>植被覆盖率最高，风景秀丽。</p><ul><li><strong>门票</strong>：40元</li><li><strong>建议时长</strong>：4-5小时</li><li><strong>看点</strong>：滑道、缆车、野长城</li></ul><h3 id="司马台长城" tabindex="-1"><a href="/beijing-travel-guide/landmarks/simatai.html">司马台长城</a> <a class="header-anchor" href="#司马台长城" aria-label="Permalink to &quot;[司马台长城](/landmarks/simatai)&quot;">​</a></h3><p>保存最原始，夜景独特。</p><ul><li><strong>门票</strong>：40元</li><li><strong>建议时长</strong>：半天</li><li><strong>看点</strong>：夜游长城、古北水镇</li></ul><h3 id="居庸关" tabindex="-1"><a href="/beijing-travel-guide/landmarks/juyongguan.html">居庸关</a> <a class="header-anchor" href="#居庸关" aria-label="Permalink to &quot;[居庸关](/landmarks/juyongguan)&quot;">​</a></h3><p>&quot;天下第一雄关&quot;，云台石刻。</p><ul><li><strong>门票</strong>：35元</li><li><strong>建议时长</strong>：2-3小时</li><li><strong>看点</strong>：云台、关城、云台石刻</li></ul><h2 id="古城遗迹" tabindex="-1">古城遗迹 <a class="header-anchor" href="#古城遗迹" aria-label="Permalink to &quot;古城遗迹&quot;">​</a></h2><h3 id="明城墙遗址" tabindex="-1"><a href="/beijing-travel-guide/landmarks/city-wall.html">明城墙遗址</a> <a class="header-anchor" href="#明城墙遗址" aria-label="Permalink to &quot;[明城墙遗址](/landmarks/city-wall)&quot;">​</a></h3><p>北京仅存的一段明城墙。</p><ul><li><strong>门票</strong>：10元</li><li><strong>看点</strong>：东南角楼、城墙遗址</li></ul><h3 id="前门大街" tabindex="-1"><a href="/beijing-travel-guide/landmarks/qianmen.html">前门大街</a> <a class="header-anchor" href="#前门大街" aria-label="Permalink to &quot;[前门大街](/landmarks/qianmen)&quot;">​</a></h3><p>老北京商业街，百年老字号。</p><ul><li><strong>门票</strong>：免费</li><li><strong>看点</strong>：正阳门、铛铛车、老字号</li></ul><h3 id="钟鼓楼" tabindex="-1"><a href="/beijing-travel-guide/landmarks/drum-tower.html">钟鼓楼</a> <a class="header-anchor" href="#钟鼓楼" aria-label="Permalink to &quot;[钟鼓楼](/landmarks/drum-tower)&quot;">​</a></h3><p>古代报时中心，老北京地标。</p><ul><li><strong>门票</strong>：联票30元</li><li><strong>看点</strong>：鼓楼、钟楼、击鼓表演</li></ul><h2 id="游览建议" tabindex="-1">游览建议 <a class="header-anchor" href="#游览建议" aria-label="Permalink to &quot;游览建议&quot;">​</a></h2><h3 id="经典三日游" tabindex="-1">经典三日游 <a class="header-anchor" href="#经典三日游" aria-label="Permalink to &quot;经典三日游&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">天数</th><th style="text-align:left;">上午</th><th style="text-align:left;">下午</th><th style="text-align:left;">晚上</th></tr></thead><tbody><tr><td style="text-align:center;">Day1</td><td style="text-align:left;">天安门广场</td><td style="text-align:left;">故宫博物院</td><td style="text-align:left;">王府井</td></tr><tr><td style="text-align:center;">Day2</td><td style="text-align:left;">八达岭长城</td><td style="text-align:left;">明十三陵</td><td style="text-align:left;">后海酒吧街</td></tr><tr><td style="text-align:center;">Day3</td><td style="text-align:left;">天坛</td><td style="text-align:left;">颐和园</td><td style="text-align:left;">前门大街</td></tr></tbody></table><h3 id="门票预约须知" tabindex="-1">门票预约须知 <a class="header-anchor" href="#门票预约须知" aria-label="Permalink to &quot;门票预约须知&quot;">​</a></h3><ol><li><strong>故宫</strong>：必须提前7天预约，现场不售票</li><li><strong>国博</strong>：提前1-7天预约，周一闭馆</li><li><strong>长城</strong>：建议提前预约，旺季限流</li><li><strong>颐和园/天坛</strong>：可现场购票，但旺季建议预约</li></ol><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ul><li>穿舒适的鞋子，每天步行量很大</li><li>带足饮水，景区内水较贵</li><li>注意防晒，夏季北京紫外线强</li><li>保管好证件，很多景点需刷身份证</li></ul><hr><p><strong>💡 提示</strong>：点击景点名称查看详细介绍和攻略</p>',54)])])}const b=t(i,[["render",n]]);export{m as __pageData,b as default};
